export type NotificationChannel = 'email' | 'sms' | 'webhook';
export type NotificationPriority = 'urgent' | 'normal' | 'low';

export interface NotificationEvent {
  type: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  priority?: NotificationPriority;
}

export interface NotificationEventMap {
  'notification:send': NotificationEvent;
}

const PRIORITY_CHANNEL_MAP: Record<NotificationPriority, NotificationChannel> = {
  urgent: 'sms',
  normal: 'email',
  low: 'webhook',
};

export function resolveChannelByPriority(priority: NotificationPriority): NotificationChannel {
  return PRIORITY_CHANNEL_MAP[priority];
}

