/**
 * Audit logging service — records every notification dispatched through the system.
 *
 * Subscribes to the notification event bus and maintains an append-only audit log.
 * Each entry captures the channel, recipient, subject, timestamp, and priority.
 */

import type { NotificationEventBus } from '../utils/event-bus.js';
import type { NotificationEvent, NotificationEventMap } from './notification.service.js';
import { Logger } from '../utils/logger.js';

export interface AuditLogEntry {
  id: string;
  channel: string;
  recipient: string;
  subject: string;
  body: string;
  priority?: string;
  timestamp: Date;
}

let nextAuditId = 1;

function generateAuditId(): string {
  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
}

export function resetAuditIdCounter(): void {
  nextAuditId = 1;
}

export class AuditService {
  private logger = new Logger('AuditService');
  private entries: AuditLogEntry[] = [];

  constructor(notificationBus: NotificationEventBus<NotificationEventMap>) {
    notificationBus.subscribe('notification:send', (event: NotificationEvent) => {
      this.record(event);
    });
  }

  private record(event: NotificationEvent): void {
    const entry: AuditLogEntry = {
      id: generateAuditId(),
      channel: event.type,
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      priority: event.priority,
      timestamp: new Date(),
    };
    this.entries.push(entry);
    this.logger.info(`Audit log: ${entry.id} — ${entry.channel} to ${entry.recipient}`);
  }

  getEntries(): AuditLogEntry[] {
    return [...this.entries];
  }

  getEntriesForRecipient(recipient: string): AuditLogEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  getEntriesByChannel(channel: string): AuditLogEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  getEntryCount(): number {
    return this.entries.length;
  }

  clear(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service — manages per-user channel preferences.
 *
 * When a user has a preference set, it overrides the default priority-based
 * channel routing. For example, a user can opt to receive all notifications
 * via SMS regardless of priority level.
 */

import type { NotificationChannel } from './notification.service.js';
import { Logger } from '../utils/logger.js';

export class NotificationPreferencesService {
  private logger = new Logger('NotificationPreferencesService');
  private preferences = new Map<string, NotificationChannel>();

  /**
   * Set a user's preferred notification channel.
   * The recipient key should match what's used in notifications (e.g., email address or userId).
   */
  setPreference(recipient: string, channel: NotificationChannel): void {
    this.preferences.set(recipient, channel);
    this.logger.info(`Preference set: ${recipient} → ${channel}`);
  }

  /**
   * Get a user's preferred notification channel, or undefined if not set.
   */
  getPreference(recipient: string): NotificationChannel | undefined {
    return this.preferences.get(recipient);
  }

  /**
   * Remove a user's notification channel preference.
   */
  removePreference(recipient: string): boolean {
    const removed = this.preferences.delete(recipient);
    if (removed) {
      this.logger.info(`Preference removed: ${recipient}`);
    }
    return removed;
  }

  /**
   * Check if a user has a channel preference set.
   */
  hasPreference(recipient: string): boolean {
    return this.preferences.has(recipient);
  }

  /**
   * Get all stored preferences (for testing/debugging).
   */
  getAllPreferences(): Map<string, NotificationChannel> {
    return new Map(this.preferences);
  }

  /**
   * Clear all preferences.
   */
  clear(): void {
    this.preferences.clear();
  }
}

