import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  EmailChannelHandler,
  SmsChannelHandler,
  WebhookChannelHandler,
  resetNotificationIdCounter,
  resolveChannelByPriority,
} from '../../src/services/notification.service.js';
import type { NotificationEventMap } from '../../src/services/notification.service.js';
import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import { NotificationEventBus } from '../../src/utils/event-bus.js';
import type { OrderCreatedEvent } from '../../src/events/event-types.js';

describe('Priority-based routing', () => {
  it('should map urgent to sms', () => {
    expect(resolveChannelByPriority('urgent')).toBe('sms');
  });

  it('should map normal to email', () => {
    expect(resolveChannelByPriority('normal')).toBe('email');
  });

  it('should map low to webhook', () => {
    expect(resolveChannelByPriority('low')).toBe('webhook');
  });
});

describe('Notification integration: priority routing → channel selection → audit log', () => {
  let eventBus: EventBus;
  let notificationBus: NotificationEventBus<NotificationEventMap>;
  let preferencesService: NotificationPreferencesService;
  let service: NotificationService;
  let emailHandler: EmailChannelHandler;
  let smsHandler: SmsChannelHandler;
  let webhookHandler: WebhookChannelHandler;
  let auditService: AuditService;

  beforeEach(() => {
    eventBus = new EventBus();
    notificationBus = new NotificationEventBus<NotificationEventMap>();
    preferencesService = new NotificationPreferencesService();
    statusChangeCallbacks.clear();

    service = new NotificationService(eventBus, notificationBus, preferencesService);
    emailHandler = new EmailChannelHandler(notificationBus);
    smsHandler = new SmsChannelHandler(notificationBus);
    webhookHandler = new WebhookChannelHandler(notificationBus);
    auditService = new AuditService(notificationBus);

    resetNotificationIdCounter();
    resetAuditIdCounter();
  });

  describe('default priority routing (no user preferences)', () => {
    it('should route urgent notifications to SMS and log to audit', () => {
      service.sendNotification({
        priority: 'urgent',
        recipient: 'alice@example.com',
        subject: 'Urgent Alert',
        body: 'Your server is down!',
      });

      // SMS handler should receive the notification
      expect(smsHandler.getSentCount()).toBe(1);
      expect(smsHandler.getSentMessages()[0]?.recipient).toBe('alice@example.com');

      // Email and webhook should NOT receive it
      expect(emailHandler.getSentCount()).toBe(0);
      expect(webhookHandler.getSentCount()).toBe(0);

      // Audit log should have an entry
      expect(auditService.getEntryCount()).toBe(1);
      const auditEntry = auditService.getEntries()[0]!;
      expect(auditEntry.channel).toBe('sms');
      expect(auditEntry.recipient).toBe('alice@example.com');
      expect(auditEntry.priority).toBe('urgent');
    });

    it('should route normal notifications to email and log to audit', () => {
      service.sendNotification({
        priority: 'normal',
        recipient: 'bob@example.com',
        subject: 'Order Update',
        body: 'Your order has shipped.',
      });

      expect(emailHandler.getSentCount()).toBe(1);
      expect(emailHandler.getSentEmails()[0]?.recipient).toBe('bob@example.com');
      expect(smsHandler.getSentCount()).toBe(0);
      expect(webhookHandler.getSentCount()).toBe(0);

      expect(auditService.getEntryCount()).toBe(1);
      expect(auditService.getEntries()[0]!.channel).toBe('email');
      expect(auditService.getEntries()[0]!.priority).toBe('normal');
    });

    it('should route low-priority notifications to webhook and log to audit', () => {
      service.sendNotification({
        priority: 'low',
        recipient: 'https://hooks.example.com/abc',
        subject: 'Weekly Digest',
        body: 'Here is your weekly summary.',
      });

      expect(webhookHandler.getSentCount()).toBe(1);
      expect(webhookHandler.getSentWebhooks()[0]?.recipient).toBe('https://hooks.example.com/abc');
      expect(emailHandler.getSentCount()).toBe(0);
      expect(smsHandler.getSentCount()).toBe(0);

      expect(auditService.getEntryCount()).toBe(1);
      expect(auditService.getEntries()[0]!.channel).toBe('webhook');
      expect(auditService.getEntries()[0]!.priority).toBe('low');
    });
  });

  describe('user preference overrides priority routing', () => {
    it('should route to SMS when user prefers SMS, even for normal priority', () => {
      preferencesService.setPreference('alice@example.com', 'sms');

      service.sendNotification({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Order Update',
        body: 'Your order has shipped.',
      });

      // Should go to SMS (user preference) instead of email (normal priority default)
      expect(smsHandler.getSentCount()).toBe(1);
      expect(emailHandler.getSentCount()).toBe(0);

      const auditEntry = auditService.getEntries()[0]!;
      expect(auditEntry.channel).toBe('sms');
      expect(auditEntry.priority).toBe('normal');
    });

    it('should route to webhook when user prefers webhook, even for urgent priority', () => {
      preferencesService.setPreference('bob@example.com', 'webhook');

      service.sendNotification({
        priority: 'urgent',
        recipient: 'bob@example.com',
        subject: 'Critical Alert',
        body: 'Immediate action needed.',
      });

      expect(webhookHandler.getSentCount()).toBe(1);
      expect(smsHandler.getSentCount()).toBe(0);

      expect(auditService.getEntries()[0]!.channel).toBe('webhook');
    });

    it('should route to email when user prefers email, even for low priority', () => {
      preferencesService.setPreference('carol@example.com', 'email');

      service.sendNotification({
        priority: 'low',
        recipient: 'carol@example.com',
        subject: 'Digest',
        body: 'Weekly summary.',
      });

      expect(emailHandler.getSentCount()).toBe(1);
      expect(webhookHandler.getSentCount()).toBe(0);

      expect(auditService.getEntries()[0]!.channel).toBe('email');
    });

    it('should fall back to priority routing when preference is removed', () => {
      preferencesService.setPreference('alice@example.com', 'sms');
      preferencesService.removePreference('alice@example.com');

      service.sendNotification({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Update',
        body: 'Back to default.',
      });

      // Should fall back to email (normal priority default)
      expect(emailHandler.getSentCount()).toBe(1);
      expect(smsHandler.getSentCount()).toBe(0);
    });
  });

  describe('end-to-end: event → priority routing → channel → audit', () => {
    it('should route order:created through normal priority to email with audit entry', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-100',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Email handler receives the notification (normal priority → email)
      expect(emailHandler.getSentCount()).toBe(1);
      const email = emailHandler.getSentEmails()[0]!;
      expect(email.recipient).toBe('alice@example.com');
      expect(email.subject).toContain('Order Confirmation');
      expect(email.body).toContain('Widget x2');
      expect(email.body).toContain('$20.00');

      // Audit log records the dispatch
      expect(auditService.getEntryCount()).toBe(1);
      const audit = auditService.getEntries()[0]!;
      expect(audit.channel).toBe('email');
      expect(audit.recipient).toBe('alice@example.com');
      expect(audit.subject).toContain('Order Confirmation');
    });

    it('should override order:created channel when user prefers SMS', async () => {
      preferencesService.setPreference('alice@example.com', 'sms');

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-200',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Gadget', quantity: 1, unitPrice: 50 },
          ],
          total: 50,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // SMS handler receives it (user preference overrides normal→email)
      expect(smsHandler.getSentCount()).toBe(1);
      expect(emailHandler.getSentCount()).toBe(0);

      // Audit log records sms channel
      expect(auditService.getEntries()[0]!.channel).toBe('sms');
    });

    it('should create audit entries for multiple notifications', () => {
      service.sendNotification({
        priority: 'urgent',
        recipient: 'user-a@example.com',
        subject: 'Alert 1',
        body: 'First alert',
      });

      service.sendNotification({
        priority: 'normal',
        recipient: 'user-b@example.com',
        subject: 'Update 1',
        body: 'First update',
      });

      service.sendNotification({
        priority: 'low',
        recipient: 'https://hooks.example.com/xyz',
        subject: 'Digest 1',
        body: 'First digest',
      });

      expect(auditService.getEntryCount()).toBe(3);
      expect(auditService.getEntriesByChannel('sms')).toHaveLength(1);
      expect(auditService.getEntriesByChannel('email')).toHaveLength(1);
      expect(auditService.getEntriesByChannel('webhook')).toHaveLength(1);

      // Verify sequential IDs
      const entries = auditService.getEntries();
      expect(entries[0]!.id).toBe('audit-0001');
      expect(entries[1]!.id).toBe('audit-0002');
      expect(entries[2]!.id).toBe('audit-0003');
    });
  });
});

describe('AuditService', () => {
  let notificationBus: NotificationEventBus<NotificationEventMap>;
  let auditService: AuditService;

  beforeEach(() => {
    notificationBus = new NotificationEventBus<NotificationEventMap>();
    auditService = new AuditService(notificationBus);
    resetAuditIdCounter();
  });

  it('should record notification events', async () => {
    await notificationBus.publish('notification:send', {
      type: 'email',
      recipient: 'test@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
    });

    expect(auditService.getEntryCount()).toBe(1);
    const entry = auditService.getEntries()[0]!;
    expect(entry.channel).toBe('email');
    expect(entry.recipient).toBe('test@example.com');
    expect(entry.subject).toBe('Test');
    expect(entry.body).toBe('Test body');
    expect(entry.priority).toBe('normal');
    expect(entry.timestamp).toBeInstanceOf(Date);
  });

  it('should filter entries by recipient', async () => {
    await notificationBus.publish('notification:send', {
      type: 'email',
      recipient: 'alice@example.com',
      subject: 'For Alice',
      body: 'Hi Alice',
    });
    await notificationBus.publish('notification:send', {
      type: 'sms',
      recipient: 'bob@example.com',
      subject: 'For Bob',
      body: 'Hi Bob',
    });

    expect(auditService.getEntriesForRecipient('alice@example.com')).toHaveLength(1);
    expect(auditService.getEntriesForRecipient('bob@example.com')).toHaveLength(1);
    expect(auditService.getEntriesForRecipient('nobody@example.com')).toHaveLength(0);
  });

  it('should filter entries by channel', async () => {
    await notificationBus.publish('notification:send', {
      type: 'email',
      recipient: 'a@example.com',
      subject: 'E',
      body: 'E',
    });
    await notificationBus.publish('notification:send', {
      type: 'sms',
      recipient: 'b@example.com',
      subject: 'S',
      body: 'S',
    });

    expect(auditService.getEntriesByChannel('email')).toHaveLength(1);
    expect(auditService.getEntriesByChannel('sms')).toHaveLength(1);
    expect(auditService.getEntriesByChannel('webhook')).toHaveLength(0);
  });

  it('should clear entries', async () => {
    await notificationBus.publish('notification:send', {
      type: 'email',
      recipient: 'test@example.com',
      subject: 'Test',
      body: 'Test',
    });

    auditService.clear();
    expect(auditService.getEntryCount()).toBe(0);
  });
});

describe('NotificationPreferencesService', () => {
  let preferencesService: NotificationPreferencesService;

  beforeEach(() => {
    preferencesService = new NotificationPreferencesService();
  });

  it('should set and get preferences', () => {
    preferencesService.setPreference('alice@example.com', 'sms');
    expect(preferencesService.getPreference('alice@example.com')).toBe('sms');
  });

  it('should return undefined for unset preferences', () => {
    expect(preferencesService.getPreference('unknown@example.com')).toBeUndefined();
  });

  it('should remove preferences', () => {
    preferencesService.setPreference('alice@example.com', 'email');
    expect(preferencesService.removePreference('alice@example.com')).toBe(true);
    expect(preferencesService.getPreference('alice@example.com')).toBeUndefined();
  });

  it('should return false when removing non-existent preference', () => {
    expect(preferencesService.removePreference('none@example.com')).toBe(false);
  });

  it('should check if preference exists', () => {
    preferencesService.setPreference('alice@example.com', 'webhook');
    expect(preferencesService.hasPreference('alice@example.com')).toBe(true);
    expect(preferencesService.hasPreference('bob@example.com')).toBe(false);
  });

  it('should override existing preferences', () => {
    preferencesService.setPreference('alice@example.com', 'email');
    preferencesService.setPreference('alice@example.com', 'sms');
    expect(preferencesService.getPreference('alice@example.com')).toBe('sms');
  });

  it('should clear all preferences', () => {
    preferencesService.setPreference('alice@example.com', 'email');
    preferencesService.setPreference('bob@example.com', 'sms');
    preferencesService.clear();
    expect(preferencesService.getAllPreferences().size).toBe(0);
  });
});

