+/**
+ * Audit logging service — records every notification dispatched through the system.
+ *
+ * Subscribes to the notification event bus and maintains an append-only audit log.
+ * Each entry captures the channel, recipient, subject, timestamp, and priority.
+ */
+
+import type { NotificationEventBus } from '../utils/event-bus.js';
+import type { NotificationEvent, NotificationEventMap } from './notification.service.js';
+import { Logger } from '../utils/logger.js';
+
+export interface AuditLogEntry {
+  id: string;
+  channel: string;
+  recipient: string;
+  subject: string;
+  body: string;
+  priority?: string;
+  timestamp: Date;
+}
+
+let nextAuditId = 1;
+
+function generateAuditId(): string {
+  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
+}
+
+export function resetAuditIdCounter(): void {
+  nextAuditId = 1;
+}
+
+export class AuditService {
+  private logger = new Logger('AuditService');
+  private entries: AuditLogEntry[] = [];
+
+  constructor(notificationBus: NotificationEventBus<NotificationEventMap>) {
+    notificationBus.subscribe('notification:send', (event: NotificationEvent) => {
+      this.record(event);
+    });
+  }
+
+  private record(event: NotificationEvent): void {
+    const entry: AuditLogEntry = {
+      id: generateAuditId(),
+      channel: event.type,
+      recipient: event.recipient,
+      subject: event.subject,
+      body: event.body,
+      priority: event.priority,
+      timestamp: new Date(),
+    };
+    this.entries.push(entry);
+    this.logger.info(`Audit log: ${entry.id} — ${entry.channel} to ${entry.recipient}`);
+  }
+
+  getEntries(): AuditLogEntry[] {
+    return [...this.entries];
+  }
+
+  getEntriesForRecipient(recipient: string): AuditLogEntry[] {
+    return this.entries.filter((e) => e.recipient === recipient);
+  }
+
+  getEntriesByChannel(channel: string): AuditLogEntry[] {
+    return this.entries.filter((e) => e.channel === channel);
+  }
+
+  getEntryCount(): number {
+    return this.entries.length;
+  }
+
+  clear(): void {
+    this.entries = [];
+  }
+}

