+/**
+ * Notification preferences service — manages per-user channel preferences.
+ *
+ * When a user has a preference set, it overrides the default priority-based
+ * channel routing. For example, a user can opt to receive all notifications
+ * via SMS regardless of priority level.
+ */
+
+import type { NotificationChannel } from './notification.service.js';
+import { Logger } from '../utils/logger.js';
+
+export class NotificationPreferencesService {
+  private logger = new Logger('NotificationPreferencesService');
+  private preferences = new Map<string, NotificationChannel>();
+
+  /**
+   * Set a user's preferred notification channel.
+   * The recipient key should match what's used in notifications (e.g., email address or userId).
+   */
+  setPreference(recipient: string, channel: NotificationChannel): void {
+    this.preferences.set(recipient, channel);
+    this.logger.info(`Preference set: ${recipient} → ${channel}`);
+  }
+
+  /**
+   * Get a user's preferred notification channel, or undefined if not set.
+   */
+  getPreference(recipient: string): NotificationChannel | undefined {
+    return this.preferences.get(recipient);
+  }
+
+  /**
+   * Remove a user's notification channel preference.
+   */
+  removePreference(recipient: string): boolean {
+    const removed = this.preferences.delete(recipient);
+    if (removed) {
+      this.logger.info(`Preference removed: ${recipient}`);
+    }
+    return removed;
+  }
+
+  /**
+   * Check if a user has a channel preference set.
+   */
+  hasPreference(recipient: string): boolean {
+    return this.preferences.has(recipient);
+  }
+
+  /**
+   * Get all stored preferences (for testing/debugging).
+   */
+  getAllPreferences(): Map<string, NotificationChannel> {
+    return new Map(this.preferences);
+  }
+
+  /**
+   * Clear all preferences.
+   */
+  clear(): void {
+    this.preferences.clear();
+  }
+}

